var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"손님을 초대할 때는 얼굴을 마주하라고 가르치지 않았나요?","JPN":"お客様を招待した際は顔を合わせてお出迎えするようにと教えたはずです。","ENG":"Have I not taught you to present yourself visibly when greeting a guest?","TWN":"我記得我教過你，招待客人時要親自迎接才是。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이제 와서 도망칠 생각은 없습니다. 어서 나오시죠.","JPN":"ここまで来て逃げるつもりはありません。出てきてください。","ENG":"I have no intention to flee at this point. Show yourself.","TWN":"我既然來了，就沒想過要逃走，快出來吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"실례를 저질렀네요.","JPN":"失礼しました。","ENG":"That was rude of me.","TWN":"真是失禮了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"하지만 이것도 당신이 너무 느릿느릿 움직인 탓 아닐까요?","JPN":"ですが、これもあなたがあまりにものんびりしていたせいですよ？","ENG":"But this is all because you've been moving far too slowly.","TWN":"不過，還不是因為你動作太慢？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"너무 늦으시는 것 같아서 기껏 고용한 용병들도 해산시키려던 참이었거든요.","JPN":"あまりにも遅いから、せっかく雇った傭兵も解散させようとしていたところです。","ENG":"I was about to dismiss the mercenaries I went through the trouble of hiring because you were running so late.","TWN":"慢到我差點就要把雇傭的傭兵都給解散了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 결과적으로 이렇게 무사히 도착했죠.","JPN":"しかし、結果的にはこのように無事到着しました。","ENG":"But ultimately, here I am, in one piece.","TWN":"我這不是來了嗎。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"당신에게는 아쉽겠네요. 제 발을 묶기 위해 한 준비들이 다 소용없게 되어 버려서.","JPN":"残念ですね。私を足止めしようと用意したものが全部無駄になってしまって。","ENG":"You must be disappointed, given how all your preparation to pin me down has been rendered futile.","TWN":"你準備了這麼多，都沒能阻止我來到這裡，是不是感到很可惜。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"나쁜 솜씨는 아니었지만 여전히 마무리가 아쉬워요, 릴리.","JPN":"悪くありませんが相変わらず詰めが甘いです、リリー。","ENG":"That wasn't half bad, but as usual, your finishing touch was a bit lacking, Lily.","TWN":"雖然有長進，但收尾不怎麼樣，莉莉。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......전 당신이 나타나기만 기다리고 있었습니다. 무슨 말을 하는지 모르겠네요.","JPN":"……私はずっとあなたが現れるのを待っていました。何を言っているのか分かりませんね。","ENG":"I was actually waiting for you to appear. I have no idea what you're talking about.","TWN":"……我一直在等你到來，真不明白你在說什麼。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......?","JPN":"……？","ENG":"......?","TWN":"……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"리코리스, 그 꼬마를 끌고 와요.","JPN":"リコリス、あのチビを連れてきてください。","ENG":"Bring me the girl, Lycoris.","TWN":"莉克麗絲，把那個小孩子帶過來。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"네, 네. 여기 대령했어.","JPN":"はいはい、ここにいるよ。","ENG":"Yeah, yeah. Here she is.","TWN":"是，是。我帶來了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"메, 메이드장님! 제성함다......! 많이 안 다치셨슴까?!","JPN":"メ、メイド長！　申し訳ないっす！　怪我は大丈夫っすか？","ENG":"C-Chief Maid! I'm so sorry, ma'am! Have they hurt you?","TWN":"女、女僕長大人！對不起……！你沒受傷吧？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"걱정해 줘서 고마워요, 모네. 보다시피 저는 무사해요.","JPN":"心配かけましたね、モネ。ありがとうございます、私は無事です。","ENG":"Thank you for your concerns, Mone. As you can see, I'm perfectly fine.","TWN":"謝謝你的關心，莫妮。如你所見，我沒事。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"기억을 잃었다더니 하는 짓은 더 가증스러워졌네요.","JPN":"記憶を失ったとはいえ、その善人ぶりは見てられませんね。","ENG":"Your amnesia has made you even more detestable.","TWN":"我聽說你失憶了，可你的一舉一動變得更加令人厭惡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저한테는 항상 메이드답게 굴라고 입 한 번 마음대로 뻥긋 못 하게 다그치던 주제에......","JPN":"私にはいつもメイドらしく、無駄口を叩かないようにと叱っていたくせに……","ENG":"You were always so strict with me, telling me that a maid should watch her every move and word...","TWN":"之前你一直讓我盡好女僕的本分，不讓我有一絲懈怠……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이 꼬마가...... 대체 뭐라고 그렇게 애지중지하는 거죠?","JPN":"このチビのことを……なぜそんなに大事にするのですか？","ENG":"And yet you indulge this child like this... Who is she to you?","TWN":"這個小孩子……你為什麼這麼在乎她？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};